'use client';

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { supabase } from '@/lib/supabase';

interface User {
  id: string;
  name: string;
  role: 'admin' | 'empleado';
  business_id?: string;
}

interface AppState {
  user: User | null;
  loading: boolean;
  transactions: any[];
  businesses: any[];
  categories: any[];
  shifts: any[];
  activeShiftBusinessId: string | null;
  currentBusinessId: string | 'all';
  timeFilter: 'daily' | 'monthly' | 'weekly';
}

interface AppContextType extends AppState {
  setUser: (user: User | null) => void;
  setTransactions: (trx: any[]) => void;
  setTimeFilter: (filter: 'daily' | 'monthly' | 'weekly') => void;
  setCurrentBusinessId: (id: string | 'all') => void;
  refreshData: () => Promise<void>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: ReactNode }) {
  const [state, setState] = useState<AppState>({
    user: null,
    loading: true,
    transactions: [],
    businesses: [],
    categories: [],
    shifts: [],
    activeShiftBusinessId: null,
    currentBusinessId: 'all',
    timeFilter: 'monthly',
  });

  const refreshData = async () => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        setState(prev => ({ ...prev, loading: false }));
        return;
      }

      // Load Profile
      const { data: profile } = await supabase.from('users').select('*').eq('id', session.user.id).maybeSingle();
      const user = profile || { id: session.user.id, name: 'Admin', role: 'admin' };

      // Load Businesses & Categories
      const [busRes, catRes] = await Promise.all([
        supabase.from('businesses').select('*'),
        supabase.from('categories').select('*'),
      ]);

      // Active Shift Check
      const { data: activeShiftBusId } = await supabase.rpc('get_active_shift', {
        p_user_id: user.id,
        p_current_time: new Date().toISOString()
      });

      let currentBusinessId = state.currentBusinessId;
      if (activeShiftBusId) {
        currentBusinessId = activeShiftBusId;
      } else if (user.role === 'empleado' && user.business_id) {
        currentBusinessId = user.business_id;
      }

      // Load Transactions
      let trxQuery = supabase.from('transactions').select('*').order('date', { ascending: false });
      if (currentBusinessId !== 'all') {
        trxQuery = trxQuery.eq('business_id', currentBusinessId);
      }
      const { data: trx } = await trxQuery.limit(1000);

      // Admin Data
      let shifts = [];
      if (user.role === 'admin') {
        const { data: shRes } = await supabase.from('shifts').select('*, businesses(name)').order('start_time', { ascending: false });
        shifts = shRes || [];
      }

      setState({
        user,
        loading: false,
        transactions: trx || [],
        businesses: busRes.data || [],
        categories: catRes.data || [],
        shifts,
        activeShiftBusinessId: activeShiftBusId,
        currentBusinessId,
        timeFilter: state.timeFilter,
      });
    } catch (error) {
      console.error('Error refreshing data:', error);
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  const value = {
    ...state,
    setUser: (user: User | null) => setState(prev => ({ ...prev, user })),
    setTransactions: (transactions: any[]) => setState(prev => ({ ...prev, transactions })),
    setTimeFilter: (timeFilter: 'daily' | 'monthly' | 'weekly') => setState(prev => ({ ...prev, timeFilter })),
    setCurrentBusinessId: (currentBusinessId: string | 'all') => setState(prev => ({ ...prev, currentBusinessId })),
    refreshData,
  };

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
}

export function useAppContext() {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useAppContext must be used within an AppProvider');
  }
  return context;
}
